from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1
import os

# Instantiate the client for Google Cloud Storage, Firestore and Pub/Sub
storage_client = storage.Client()
db = firestore.Client()
publisher = pubsub_v1.PublisherClient()

def hello_gcs(data, context):
    """Cloud Function to be triggered by Cloud Storage events.
    Args:
        data (dict): Event payload.
        context (google.cloud.functions.Context): Metadata for the event.
    """
    file = storage_client.bucket(data['bucket']).get_blob(data['name'])
    
    # Processing files goes here
    
    # Write to Firestore
    doc_ref = db.collection('myCollection').document()
    doc_ref.set({
        'fileName': file.name,
        'contentType': file.content_type,
        'size': file.size,
        'createTime': file.time_created
    })
    
    # Publish to Pub/Sub topic
    publisher.publish(os.getenv('TOPIC_NAME'), f'File {file.name} was uploaded at {str(file.time_created)}'.encode())